/**
 * Verify the HMAC signature of a message to ensure it came from an authorized publisher.
 * Messages MUST be signed by publishers using the shared HMAC secret.
 */
function verifyMessageSignature(messageBody, signature) {
  if (!signature || typeof signature !== 'string') {
    return false;
  }

  const expectedSignature = crypto
    .createHmac('sha256', HMAC_SECRET)
    .update(messageBody)
    .digest('hex');

  // Use timing-safe comparison to prevent timing attacks
  if (signature.length !== expectedSignature.length) {
    return false;
  }

  return crypto.timingSafeEqual(
    Buffer.from(signature, 'hex'),
    Buffer.from(expectedSignature, 'hex')
  );
}

